+			mu.Lock()
+			if err != nil {
+				results = append(results, ClusterResult{
+					Cluster: name,
+					Error:   err.Error(),
+				})
+			} else {
+				results = append(results, ClusterResult{
+					Cluster: name,
+					Result:  result,
+				})
